import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Deal {
  productName: string;
  originalPrice: number;
  discountedPrice: number;
  discountPercent: number;
  expiryCountdown: string;
}

interface DealsData {
  topDeals: Deal[];
}

export default function Widget() {
  const { topDeals } = response.data as DealsData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: theme === 'dark' ? '#2D2D2D' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" sx={{ color: primaryColor, fontWeight: 600 }}>
            Top Deals
          </Typography>
          {topDeals.map((deal, index) => (
            <Box key={index} sx={{ bgcolor: '#333333', borderRadius: 1, p: 1.5 }}>
              <Stack direction="row" justifyContent="space-between" alignItems="center">
                <Typography variant="body1" sx={{ color: '#FFFFFF', fontWeight: 500 }}>
                  {deal.productName}
                </Typography>
                <Chip label={`-${deal.discountPercent}%`} sx={{ bgcolor: accentColor, color: '#000', fontWeight: 600 }} />
              </Stack>
              <Stack direction="row" justifyContent="space-between" sx={{ mt: 0.5 }}>
                <Typography variant="body2" sx={{ color: '#B0B0B0' }}>
                  <s>${deal.originalPrice.toFixed(2)}</s>
                </Typography>
                <Typography variant="body2" sx={{ color: '#FFEB3B', fontWeight: 600 }}>
                  ${deal.discountedPrice.toFixed(2)}
                </Typography>
              </Stack>
              <Typography variant="caption" sx={{ color: '#B0B0B0', mt: 0.5 }}>
                Ends in {deal.expiryCountdown}
              </Typography>
            </Box>
          ))}
        </Stack>
      </CardContent>
    </Card>
  );
}
